  "log" -> F.logFeature
  "test" -> F.testFeature
  "retry" -> F.retryFeature
  "timeout" -> F.timeoutFeature
  "ratelimit" -> F.ratelimitFeature
  "cache" -> F.cacheFeature
  "idempotency" -> F.idempotencyFeature
